6	
7	------------------------------------------------------------------------------
8	-- Libraries
9	------------------------------------------------------------------------------
10	
11	library ieee;
12		use ieee.std_logic_1164.all;
13		use ieee.numeric_std.all;
14	
15	library work;
16		use work.psi_common_math_pkg.all;
17		use work.psi_common_array_pkg.all;
18		use work.data_rec_register_pkg.all;
19	
20	------------------------------------------------------------------------------
21	-- Entity
22	------------------------------------------------------------------------------	
23	entity data_rec_vivado_wrp is
24		generic
25		(
26			-- Component Parameters
27			NumOfInputs_g				: positive range 1 to 8		:= 4;
28			InputWidth_g				: positive range 1 to 32	:= 8;
29			MemoryDepth_g				: positive					:= 128;
30			TrigInputs_g				: natural range 0 to 8		:= 1;
31			TrigForwarding_g			: boolean					:= false;			-- Forwarding of trigger signals to the output
32			
33			-- AXI Parameters
34			C_S00_AXI_ID_WIDTH          : integer := 1;							-- Width of ID for for write address, write data, read address and read data
35			C_S00_AXI_ADDR_WIDTH        : integer := 14							-- Width of S_AXI address bus		
36		);
37		port
38		(
39			-- Control Signals
40			Clk							: in std_logic;
41			Rst							: in std_logic;
42			-- Data Ports
43			In_Data0					: in std_logic_vector(InputWidth_g-1 downto 0);
44			In_Data1					: in std_logic_vector(InputWidth_g-1 downto 0);
45			In_Data2					: in std_logic_vector(InputWidth_g-1 downto 0);
46			In_Data3					: in std_logic_vector(InputWidth_g-1 downto 0);
47			In_Data4					: in std_logic_vector(InputWidth_g-1 downto 0);
48			In_Data5					: in std_logic_vector(InputWidth_g-1 downto 0);
49			In_Data6					: in std_logic_vector(InputWidth_g-1 downto 0);
50			In_Data7					: in std_logic_vector(InputWidth_g-1 downto 0);
51			In_Vld						: in std_logic;
52			-- Trigger Ports
53			Trig_In						: in std_logic_vector(TrigInputs_g-1 downto 0);
54			Trig_Out					: out std_logic;
55			Done_Irq					: out std_logic;
56			-----------------------------------------------------------------------------
57			-- Axi Slave Bus Interface
58			-----------------------------------------------------------------------------
59			-- System
60			s00_axi_aclk                : in    std_logic;                                             -- Global Clock Signal
61			s00_axi_aresetn             : in    std_logic;                                             -- Global Reset Signal. This signal is low active.
62			-- Read address channel
63			s00_axi_arid                : in    std_logic_vector(C_S00_AXI_ID_WIDTH-1   downto 0);     -- Read address ID. This signal is the identification tag for the read address group of signals.
64			s00_axi_araddr              : in    std_logic_vector(C_S00_AXI_ADDR_WIDTH-1 downto 0);     -- Read address. This signal indicates the initial address of a read burst transaction.
65			s00_axi_arlen               : in    std_logic_vector(7 downto 0);                          -- Burst length. The burst length gives the exact number of transfers in a burst
66			s00_axi_arsize              : in    std_logic_vector(2 downto 0);                          -- Burst size. This signal indicates the size of each transfer in the burst
67			s00_axi_arburst             : in    std_logic_vector(1 downto 0);                          -- Burst type. The burst type and the size information, determine how the address for each transfer within the burst is calculated.
68			s00_axi_arlock              : in    std_logic;                                             -- Lock type. Provides additional information about the atomic characteristics of the transfer.
69			s00_axi_arcache             : in    std_logic_vector(3 downto 0);                          -- Memory type. This signal indicates how transactions are required to progress through a system.
70			s00_axi_arprot              : in    std_logic_vector(2 downto 0);                          -- Protection type. This signal indicates the privilege and security level of the transaction, and whether the transaction is a data access or an instruction access.
71			s00_axi_arvalid             : in    std_logic;                                             -- Write address valid. This signal indicates that the channel is signaling valid read address and control information.
72			s00_axi_arready             : out   std_logic;                                             -- Read address ready. This signal indicates that the slave is ready to accept an address and associated control signals.
73			-- Read data channel
74			s00_axi_rid                 : out   std_logic_vector(C_S00_AXI_ID_WIDTH-1 downto 0);       -- Read ID tag. This signal is the identification tag for the read data group of signals generated by the slave.
75			s00_axi_rdata               : out   std_logic_vector(31 downto 0);                         -- Read Data
76			s00_axi_rresp               : out   std_logic_vector(1 downto 0);                          -- Read response. This signal indicates the status of the read transfer.
77			s00_axi_rlast               : out   std_logic;                                             -- Read last. This signal indicates the last transfer in a read burst.
78			s00_axi_rvalid              : out   std_logic;                                             -- Read valid. This signal indicates that the channel is signaling the required read data.
79			s00_axi_rready              : in    std_logic;                                             -- Read ready. This signal indicates that the master can accept the read data and response information.
80			-- Write address channel
81			s00_axi_awid                : in    std_logic_vector(C_S00_AXI_ID_WIDTH-1   downto 0);     -- Write Address ID
82			s00_axi_awaddr              : in    std_logic_vector(C_S00_AXI_ADDR_WIDTH-1 downto 0);     -- Write address
83			s00_axi_awlen               : in    std_logic_vector(7 downto 0);                          -- Burst length. The burst length gives the exact number of transfers in a burst
84			s00_axi_awsize              : in    std_logic_vector(2 downto 0);                          -- Burst size. This signal indicates the size of each transfer in the burst
85			s00_axi_awburst             : in    std_logic_vector(1 downto 0);                          -- Burst type. The burst type and the size information, determine how the address for each transfer within the burst is calculated.
86			s00_axi_awlock              : in    std_logic;                                             -- Lock type. Provides additional information about the atomic characteristics of the transfer.
87			s00_axi_awcache             : in    std_logic_vector(3 downto 0);                          -- Memory type. This signal indicates how transactions are required to progress through a system.
88			s00_axi_awprot              : in    std_logic_vector(2 downto 0);                          -- Protection type. This signal indicates the privilege and security level of the transaction, and whether the transaction is a data access or an instruction access.
89			s00_axi_awvalid             : in    std_logic;                                             -- Write address valid. This signal indicates that the channel is signaling valid write address and control information.
90			s00_axi_awready             : out   std_logic;                                             -- Write address ready. This signal indicates that the slave is ready to accept an address and associated control signals.
91			-- Write data channel
92			s00_axi_wdata               : in    std_logic_vector(31    downto 0);                      -- Write Data
93			s00_axi_wstrb               : in    std_logic_vector(3 downto 0);                          -- Write strobes. This signal indicates which byte lanes hold valid data. There is one write strobe bit for each eight bits of the write data bus.
94			s00_axi_wlast               : in    std_logic;                                             -- Write last. This signal indicates the last transfer in a write burst.
95			s00_axi_wvalid              : in    std_logic;                                             -- Write valid. This signal indicates that valid write data and strobes are available.
96			s00_axi_wready              : out   std_logic;                                             -- Write ready. This signal indicates that the slave can accept the write data.
97			-- Write response channel
98			s00_axi_bid                 : out   std_logic_vector(C_S00_AXI_ID_WIDTH-1 downto 0);       -- Response ID tag. This signal is the ID tag of the write response.
99			s00_axi_bresp               : out   std_logic_vector(1 downto 0);                          -- Write response. This signal indicates the status of the write transaction.
100			s00_axi_bvalid              : out   std_logic;                                             -- Write response valid. This signal indicates that the channel is signaling a valid write response.
101			s00_axi_bready              : in    std_logic                                              -- Response ready. This signal indicates that the master can accept a write response.		
102		);
103	
104	end entity data_rec_vivado_wrp;
105	
106	------------------------------------------------------------------------------
107	-- Architecture section
108	------------------------------------------------------------------------------
109	
110	architecture rtl of data_rec_vivado_wrp is 
111	
112		-- More complex logic is required to support non-power-of-two recorder depth
113		constant NonPwr2MemDepth_c				: boolean				:= (log2(MemoryDepth_g) /= log2ceil(MemoryDepth_g));
114	
115		-- Array of desired number of chip enables for each address range
116		constant USER_SLV_NUM_REG               : integer              := 32; 
117		
118		-- IP Interconnect (IPIC) signal declarations
119		signal reg_rd                    		: std_logic_vector(USER_SLV_NUM_REG-1 downto  0);
120		signal reg_rdata                 		: t_aslv32(0 to USER_SLV_NUM_REG-1) := (others => (others => '0'));
121		signal reg_wr                    		: std_logic_vector(USER_SLV_NUM_REG-1 downto  0);
122		signal reg_wdata                 		: t_aslv32(0 to USER_SLV_NUM_REG-1);	
123	    signal mem_addr                  		: std_logic_vector(C_S00_AXI_ADDR_WIDTH - 1 downto  0);
124	    signal mem_wr                    		: std_logic_vector( 3 downto  0);
125	    signal mem_wdata                 		: std_logic_vector(31 downto  0);
126	    signal mem_rdata                 		: std_logic_vector(31 downto  0);	
127	
128		-- Register Signals
129		signal reg_cfg_arm						: std_logic;
130		signal reg_cfg_trigcntclr				: std_logic;
131		signal reg_stat_state					: std_logic_vector(3 downto 0);
132		signal reg_pretrig						: std_logic_vector(log2ceil(MemoryDepth_g)-1 downto 0);
133		signal reg_totspl						: std_logic_vector(log2ceil(MemoryDepth_g) downto 0);
134		signal reg_selftriglo					: std_logic_vector(31 downto 0);	-- Full width for sign-correct extended readback
135		signal reg_selftrighi					: std_logic_vector(31 downto 0);	-- Full width for sign-correct extended readback
136		signal reg_selftrigchena				: std_logic_vector(NumOfInputs_g-1 downto 0);
137		signal reg_selftrigonexit				: std_logic;
138		signal reg_selftrigonenter				: std_logic;
139		signal reg_swtrig						: std_logic;
140		signal reg_trigcnt						: std_logic_vector(31 downto 0);
141		signal reg_donetime						: std_logic_vector(31 downto 0);
142		signal reg_trigena						: std_logic_vector(2 downto 0);
143		signal reg_minrecperiod					: std_logic_vector(31 downto 0);
144		signal reg_enableexttrig				: std_logic_vector(TrigInputs_g-1 downto 0);
145		
146		-- Data side signals
147		signal port_cfg_arm						: std_logic;
148		signal port_cfg_ack						: std_logic;
149		signal port_cfg_trigcntclr				: std_logic;
150		signal port_stat_state					: std_logic_vector(3 downto 0);
151		signal port_pretrig						: std_logic_vector(log2ceil(MemoryDepth_g)-1 downto 0);
152		signal port_totspl						: std_logic_vector(log2ceil(MemoryDepth_g) downto 0);
153		signal port_selftriglo					: std_logic_vector(InputWidth_g-1 downto 0);
154		signal port_selftrighi					: std_logic_vector(InputWidth_g-1 downto 0);
155		signal port_selftrigchena				: std_logic_vector(NumOfInputs_g-1 downto 0);
156		signal port_selftrigonexit				: std_logic;
157		signal port_selftrigonenter				: std_logic;	
158		signal port_swtrig						: std_logic;
159		signal port_done						: std_logic;
160		signal port_trigcnt						: std_logic_vector(31 downto 0);
161		signal port_donetime					: std_logic_vector(31 downto 0);
162		signal port_trigena						: std_logic_vector(2 downto 0);
163		signal port_minrecperiod				: std_logic_vector(31 downto 0);
164		signal port_enableexttrig				: std_logic_vector(TrigInputs_g-1 downto 0);
165		
166		-- Status CC to Axi
167		subtype CcSToAxi_StatState_Rng			is natural range 3 downto 0;	
168		subtype CcSToAxi_TrigCnt_Rng			is natural range CcSToAxi_StatState_Rng'left+32 downto CcSToAxi_StatState_Rng'left+1;
169		subtype CcSToAxi_DoneTime_Rng			is natural range CcSToAxi_TrigCnt_Rng'left+32 downto CcSToAxi_TrigCnt_Rng'left+1;
170		constant CcSToAxi_Width_c				: natural	:= CcSToAxi_DoneTime_Rng'high+1;	 
171		signal CcSToAxIn						: std_logic_vector(CcSToAxi_Width_c-1 downto 0);
172		signal CcSToAxOut						: std_logic_vector(CcSToAxi_Width_c-1 downto 0);
173		
174		-- Pulse CC from Axi
175		constant CcPFromAxi_Arm_c				: natural := 0;
176		constant CcPFromAxi_Ack_c				: natural := CcPFromAxi_Arm_c+1;
177		constant CcPFromAxi_TrigCntClr_c		: natural := CcPFromAxi_Ack_c+1;
178		constant CcFromAxi_Width_c				: natural := CcPFromAxi_TrigCntClr_c+1;
179		signal CcPFromAxIn						: std_logic_vector(CcFromAxi_Width_c-1 downto 0);
180		signal CcPFromAxOut						: std_logic_vector(CcFromAxi_Width_c-1 downto 0);
181		
182		-- Status CC from Axi
183		subtype CcSFromAxi_PreTrig_Rng			is natural range log2ceil(MemoryDepth_g)-1 downto 0;
184		subtype CcSFromAxi_TotSpl_Rng			is natural range CcSFromAxi_PreTrig_Rng'left+log2ceil(MemoryDepth_g)+1 downto CcSFromAxi_PreTrig_Rng'left+1;
185		subtype CcSFromAxi_SelfTrigLo_Rng		is natural range CcSFromAxi_TotSpl_Rng'left+InputWidth_g downto CcSFromAxi_TotSpl_Rng'left+1;
186		subtype CcSFromAxi_SelfTrigHi_Rng		is natural range CcSFromAxi_SelfTrigLo_Rng'left+InputWidth_g downto CcSFromAxi_SelfTrigLo_Rng'left+1;
187		subtype CcSFromAxi_SelfTrigChEna_Rng	is natural range CcSFromAxi_SelfTrigHi_Rng'left+NumOfInputs_g downto CcSFromAxi_SelfTrigHi_Rng'left+1;
188		constant CcSFromAxi_SelfTrigOnExit_c	: natural 	:= CcSFromAxi_SelfTrigChEna_Rng'left+1;
189		constant CcSFromAxi_SelfTrigOnEnter_c	: natural 	:= CcSFromAxi_SelfTrigOnExit_c+1;
190		subtype CcSFromAxi_TrigEna_Rng			is natural range CcSFromAxi_SelfTrigOnEnter_c+3 downto CcSFromAxi_SelfTrigOnEnter_c+1;
191		constant CcSFromAxi_SwTrig_c			: natural := CcSFromAxi_TrigEna_Rng'left+1;
192		subtype CcSFromAxi_MinRecPeriod_Rng		is natural range CcSFromAxi_SwTrig_c+32 downto CcSFromAxi_SwTrig_c+1;
193		subtype CcSFromAxi_EnableExtTrig_Rng	is natural range CcSFromAxi_MinRecPeriod_Rng'left+TrigInputs_g downto CcSFromAxi_MinRecPeriod_Rng'left+1;
194		constant CcSFromAxi_Width_c				: natural	:= CcSFromAxi_EnableExtTrig_Rng'left+1;	
195		signal CcSFromAxIn						: std_logic_vector(CcSFromAxi_Width_c-1 downto 0);
196		signal CcSFromAxOut						: std_logic_vector(CcSFromAxi_Width_c-1 downto 0);	
197		
198		-- Pulse CC to Axi
199		constant CsPToAxi_Done_c				: natural	:= 0;			
200		constant CsPToAxi_Width_c				: natural	:= CsPToAxi_Done_c+1;
201		signal CcPToAxIn						: std_logic_vector(CsPToAxi_Width_c-1 downto 0);
202		signal CcPToAxOut						: std_logic_vector(CsPToAxi_Width_c-1 downto 0);
203		
204		-- Ohter Signals 
205		signal RstProc							: std_logic;
206		signal AxiRst							: std_logic;
207		
208		-- Memory Signals
209		signal RecMemWr							: std_logic;
210		signal RecMemAdr						: std_logic_vector(log2ceil(MemoryDepth_g)-1 downto 0);
211		signal RecMemData						: std_logic_vector(InputWidth_g*NumOfInputs_g-1 downto 0);
212		signal AxiMemAdr						: std_logic_vector(log2ceil(MemoryDepth_g)-1 downto 0);
213		signal AxiMemSel						: std_logic_vector(2 downto 0);
214		type Data_t	is array (natural range <>) of std_logic_vector(InputWidth_g-1 downto 0);
215		signal AxiMemOut						: Data_t(7 downto 0);
216		
217		-- Internal Signals
218		signal FirstSplAddr						: std_logic_vector(log2ceil(MemoryDepth_g)-1 downto 0);
219		signal AckDone							: std_logic;
220		
221		-- Register Reaset Values
222		constant RegRstVal_c					: t_aslv32(0 to USER_SLV_NUM_REG-1)	:= (Reg_EnableExtTrig_Addr_c/4 => (others => '1'),	-- Enable all external triggers by default
223																						others => (others => '0'));
224		
225	
226	begin
227	
228		AxiRst <= not s00_axi_aresetn;
229	
230	   -----------------------------------------------------------------------------
231	   -- AXI decode instance
232	   -----------------------------------------------------------------------------
233	   axi_slave_reg_mem_inst : entity work.psi_common_axi_slave_ipif
234	   generic map
235	   (
236	      -- Users parameters
237	      num_reg_g                    => USER_SLV_NUM_REG,
238	      use_mem_g                    => true,
239	      rst_val_g                  => RegRstVal_c,
240	      -- Parameters of Axi Slave Bus Interface
241	      axi_id_width_g                => C_S00_AXI_ID_WIDTH,
242	      axi_addr_width_g              => C_S00_AXI_ADDR_WIDTH
243	   )
244	   port map
245	   (
246	      --------------------------------------------------------------------------
247	      -- Axi Slave Bus Interface
248	      --------------------------------------------------------------------------
249	      -- System
250	      s_axi_aclk                  => s00_axi_aclk,
251	      s_axi_aresetn               => s00_axi_aresetn,
252	      -- Read address channel
253	      s_axi_arid                  => s00_axi_arid,
254	      s_axi_araddr                => s00_axi_araddr,
255	      s_axi_arlen                 => s00_axi_arlen,
256	      s_axi_arsize                => s00_axi_arsize,
257	      s_axi_arburst               => s00_axi_arburst,
258	      s_axi_arlock                => s00_axi_arlock,
259	      s_axi_arcache               => s00_axi_arcache,
260	      s_axi_arprot                => s00_axi_arprot,
261	      s_axi_arvalid               => s00_axi_arvalid,
262	      s_axi_arready               => s00_axi_arready,
263	      -- Read data channel
264	      s_axi_rid                   => s00_axi_rid,
265	      s_axi_rdata                 => s00_axi_rdata,
266	      s_axi_rresp                 => s00_axi_rresp,
267	      s_axi_rlast                 => s00_axi_rlast,
268	      s_axi_rvalid                => s00_axi_rvalid,
269	      s_axi_rready                => s00_axi_rready,
270	      -- Write address channel
271	      s_axi_awid                  => s00_axi_awid,
272	      s_axi_awaddr                => s00_axi_awaddr,
273	      s_axi_awlen                 => s00_axi_awlen,
274	      s_axi_awsize                => s00_axi_awsize,
275	      s_axi_awburst               => s00_axi_awburst,
276	      s_axi_awlock                => s00_axi_awlock,
277	      s_axi_awcache               => s00_axi_awcache,
278	      s_axi_awprot                => s00_axi_awprot,
279	      s_axi_awvalid               => s00_axi_awvalid,
280	      s_axi_awready               => s00_axi_awready,
281	      -- Write data channel
282	      s_axi_wdata                 => s00_axi_wdata,
283	      s_axi_wstrb                 => s00_axi_wstrb,
284	      s_axi_wlast                 => s00_axi_wlast,
285	      s_axi_wvalid                => s00_axi_wvalid,
286	      s_axi_wready                => s00_axi_wready,
287	      -- Write response channel
288	      s_axi_bid                   => s00_axi_bid,
289	      s_axi_bresp                 => s00_axi_bresp,
290	      s_axi_bvalid                => s00_axi_bvalid,
291	      s_axi_bready                => s00_axi_bready,
292	      --------------------------------------------------------------------------
293	      -- Register Interface
294	      --------------------------------------------------------------------------
295	      o_reg_rd                    => reg_rd,
296	      i_reg_rdata                 => reg_rdata,
297	      o_reg_wr                    => reg_wr,
298	      o_reg_wdata                 => reg_wdata,
299		  	--------------------------------------------------------------------------
300	      -- Memory Interface
301	      --------------------------------------------------------------------------
302	      o_mem_addr                  => mem_addr,
303	      o_mem_wr                    => mem_wr,
304	      o_mem_wdata                 => mem_wdata,
305	      i_mem_rdata                 => mem_rdata
306	   );
307	
308		-----------------------------------------------------------------------------
309		-- Register Decoding
310		----------------------------------------------------------------------------   
311		-- Status
312		reg_rdata(ToWordAddr(Reg_Stat_Addr_c))(3 downto 0)		<= reg_stat_state;
313		AckDone <= '1' when (reg_rd(ToWordAddr(Reg_Stat_Addr_c)) = '1') and (unsigned(reg_stat_state) = Reg_Stat_StateDone_c) else '0';
314		
315		-- Cfg
316		reg_cfg_arm 		<= reg_wr(ToWordAddr(Reg_Cfg_Addr_c)) and reg_wdata(ToWordAddr(Reg_Cfg_Addr_c))(Reg_Cfg_ArmIdx_c);
317		reg_cfg_trigcntclr	<= reg_wr(ToWordAddr(Reg_Cfg_Addr_c)) and reg_wdata(ToWordAddr(Reg_Cfg_Addr_c))(Reg_Cfg_TrgCntClr_Idx_c);
318		reg_pretrig			<= reg_wdata(ToWordAddr(Reg_Pretrig_Addr_c))(reg_pretrig'left downto 0);
319		reg_totspl			<= reg_wdata(ToWordAddr(Reg_Totspl_Addr_c))(reg_totspl'left downto 0);
320		reg_selftriglo		<= reg_wdata(ToWordAddr(Reg_SelftrigLo_Addr_c))(reg_selftriglo'left downto 0);
321		reg_selftrighi		<= reg_wdata(ToWordAddr(Reg_SelftrigHi_Addr_c))(reg_selftrighi'left downto 0);
322		reg_selftrigchena	<= reg_wdata(ToWordAddr(Reg_SelftrigCfg_Addr_c))(NumOfInputs_g-1 downto 0);
323		reg_selftrigonexit	<= reg_wdata(ToWordAddr(Reg_SelftrigCfg_Addr_c))(Reg_SelftrigCfg_ExitSft_c);
324		reg_selftrigonenter	<= reg_wdata(ToWordAddr(Reg_SelftrigCfg_Addr_c))(Reg_SelftrigCfg_EnterSft_c);
325		reg_swtrig			<= reg_wdata(ToWordAddr(Reg_SwTrig_Addr_c))(Reg_SwTrig_TrigIdx_c);
326		reg_trigena			<= reg_wdata(ToWordAddr(Reg_TrigEna_Addr_c))(reg_trigena'left downto 0);
327		reg_minrecperiod	<= reg_wdata(ToWordAddr(Reg_MinRecPeriod_Addr_c))(reg_minrecperiod'left downto 0);
328		reg_enableexttrig	<= reg_wdata(ToWordAddr(Reg_EnableExtTrig_Addr_c))(reg_enableexttrig'left downto 0);
329		
330		-- Cfg Readback
331		reg_rdata(ToWordAddr(Reg_Pretrig_Addr_c))(reg_pretrig'left downto 0)				<= reg_pretrig;
332		reg_rdata(ToWordAddr(Reg_Totspl_Addr_c))(reg_totspl'left downto 0)					<= reg_totspl;
333		reg_rdata(ToWordAddr(Reg_SelftrigLo_Addr_c))(reg_selftriglo'left downto 0)			<= reg_selftriglo;
334		reg_rdata(ToWordAddr(Reg_SelftrigHi_Addr_c))(reg_selftrighi'left downto 0)			<= reg_selftrighi;
335		reg_rdata(ToWordAddr(Reg_SelftrigCfg_Addr_c))(NumOfInputs_g-1 downto 0)				<= reg_selftrigchena;
336		reg_rdata(ToWordAddr(Reg_SelftrigCfg_Addr_c))(Reg_SelftrigCfg_ExitSft_c)			<= reg_selftrigonexit;
337		reg_rdata(ToWordAddr(Reg_SelftrigCfg_Addr_c))(Reg_SelftrigCfg_EnterSft_c)			<= reg_selftrigonenter;	
338		reg_rdata(ToWordAddr(Reg_TrigCnt_Addr_c))(reg_trigcnt'left downto 0)				<= reg_trigcnt;
339		reg_rdata(ToWordAddr(Reg_DoneTime_Addr_c))(reg_donetime'left downto 0)				<= reg_donetime;
340		reg_rdata(ToWordAddr(Reg_TrigEna_Addr_c))(reg_trigena'left downto 0)				<= reg_trigena;
341		reg_rdata(ToWordAddr(Reg_MinRecPeriod_Addr_c))(reg_minrecperiod'left downto 0)		<= reg_minrecperiod;
342		reg_rdata(ToWordAddr(Reg_EnableExtTrig_Addr_c))(reg_enableexttrig'left downto 0)	<= reg_enableexttrig;
343		
344	   
345		-----------------------------------------------------------------------------
346		-- Clock Crossings
347		----------------------------------------------------------------------------- 
348		
349		-- *** Status from Data to AXI domain ***
350		CcSToAxIn(CcSToAxi_StatState_Rng)	<= port_stat_state;
351		CcSToAxIn(CcSToAxi_TrigCnt_Rng)		<= port_trigcnt;
352		CcSToAxIn(CcSToAxi_DoneTime_Rng)	<= port_donetime;
353		
354		i_cc_status_toAxi : entity work.psi_common_status_cc
355			generic map (
356				width_g	=> CcSToAxi_Width_c
357			)
358			port map (
359				a_clk_i		=> Clk,
360				a_rst_i		=> Rst,
361				a_rst_o 	=> RstProc,
362				a_dat_i		=> CcSToAxIn,
363				b_clk_i		=> s00_axi_aclk,
364				b_rst_i		=> AxiRst,
365				b_rst_o		=> open,
366				b_dat_o		=> CcSToAxOut			
367			);
368			
369		reg_stat_state 	<= CcSToAxOut(CcSToAxi_StatState_Rng);
370		reg_trigcnt		<= CcSToAxOut(CcSToAxi_TrigCnt_Rng);
371		reg_donetime	<= CcSToAxOut(CcSToAxi_DoneTime_Rng);
372		
373		-- *** Status from Axi to Data domain ***
374		CcSFromAxIn(CcSFromAxi_PreTrig_Rng)			<= reg_pretrig;
375		CcSFromAxIn(CcSFromAxi_TotSpl_Rng)			<= reg_totspl;
376		CcSFromAxIn(CcSFromAxi_SelfTrigLo_Rng)		<= reg_selftriglo(InputWidth_g-1 downto 0);
377		CcSFromAxIn(CcSFromAxi_SelfTrigHi_Rng)		<= reg_selftrighi(InputWidth_g-1 downto 0);
378		CcSFromAxIn(CcSFromAxi_SelfTrigChEna_Rng)	<= reg_selftrigchena;
379		CcSFromAxIn(CcSFromAxi_SelfTrigOnExit_c)	<= reg_selftrigonexit;
380		CcSFromAxIn(CcSFromAxi_SelfTrigOnEnter_c)	<= reg_selftrigonenter;	
381		CcSFromAxIn(CcSFromAxi_TrigEna_Rng)			<= reg_trigena;
382		CcSFromAxIn(CcSFromAxi_SwTrig_c)			<= reg_swtrig;
383		CcSFromAxIn(CcSFromAxi_MinRecPeriod_Rng)	<= reg_minrecperiod;
384		CcSFromAxIn(CcSFromAxi_EnableExtTrig_Rng)	<= reg_enableexttrig;
385		
386		i_cc_status_fromAxi : entity work.psi_common_status_cc
387			generic map (
388				width_g	=> CcSFromAxi_Width_c
389			)
390			port map (
391				a_clk_i		=> s00_axi_aclk,
392				a_rst_i		=> AxiRst,
393				a_rst_o 	=> open,
394				a_dat_i		=> CcSFromAxIn,
395				b_clk_i		=> Clk,
396				b_rst_i		=> Rst,
397				b_rst_o		=> open,
398				b_dat_o		=> CcSFromAxOut			
399			);
400			
401		port_pretrig 			<= CcSFromAxOut(CcSFromAxi_PreTrig_Rng);	
402		port_totspl 			<= CcSFromAxOut(CcSFromAxi_TotSpl_Rng);	
403		port_selftriglo			<= CcSFromAxOut(CcSFromAxi_SelfTrigLo_Rng);
404		port_selftrighi			<= CcSFromAxOut(CcSFromAxi_SelfTrigHi_Rng);
405		port_selftrigchena		<= CcSFromAxOut(CcSFromAxi_SelfTrigChEna_Rng);
406		port_selftrigonexit		<= CcSFromAxOut(CcSFromAxi_SelfTrigOnExit_c);
407		port_selftrigonenter	<= CcSFromAxOut(CcSFromAxi_SelfTrigOnEnter_c);
408		port_trigena			<= CcSFromAxOut(CcSFromAxi_TrigEna_Rng);
409		port_swtrig				<= CcSFromAxOut(CcSFromAxi_SwTrig_c);
410		port_minrecperiod		<= CcSFromAxOut(CcSFromAxi_MinRecPeriod_Rng);
411		port_enableexttrig		<= CcSFromAxOut(CcSFromAxi_EnableExtTrig_Rng);
412		
413		-- *** Pulses from AXI to Data domain ***
414		CcPFromAxIn(CcPFromAxi_Arm_c)			<= reg_cfg_arm;
415		CcPFromAxIn(CcPFromAxi_Ack_c)			<= AckDone;
416		CcPFromAxIn(CcPFromAxi_TrigCntClr_c)	<= reg_cfg_trigcntclr;
417		
418		i_cc_pulse_fromAxi : entity work.psi_common_pulse_cc
419			generic map (
420				num_pulses_g	=> CcFromAxi_Width_c
421			)
422			port map (
423				a_clk_i 		=> s00_axi_aclk,
424				a_rst_i		=> AxiRst,
425				a_rst_o		=> open,
426				a_dat_i		=> CcPFromAxIn,
427				b_clk_i		=> Clk,
428				b_rst_i		=> Rst,
429				b_rst_o		=> open,
430				b_dat_o		=> CcPFromAxOut
431			);
432			
433		port_cfg_arm 		<= CcPFromAxOut(CcPFromAxi_Arm_c);
434		port_cfg_ack 		<= CcPFromAxOut(CcPFromAxi_Ack_c);
435		port_cfg_trigcntclr	<= CcPFromAxOut(CcPFromAxi_TrigCntClr_c);
436		
437		-- *** Pulses from Data to Axi domain ***
438		CcPToAxIn(CsPToAxi_Done_c)			<= port_done;
439		
440		i_cc_pulse_toAxi : entity work.psi_common_pulse_cc
441			generic map (
442				num_pulses_g	=> CsPToAxi_Width_c
443			)
444			port map (
445				a_clk_i 		=> Clk,
446				a_rst_i		=> Rst,
447				a_rst_o		=> open,
448				a_dat_i		=> CcPToAxIn,
449				b_clk_i		=> s00_axi_aclk,
450				b_rst_i		=> AxiRst,
451				b_rst_o		=> open,
452				b_dat_o		=> CcPToAxOut
453			);
454			
455		Done_Irq 		<= CcPToAxOut(CsPToAxi_Done_c);
456	
457		------------------------------------------
458		-- instantiate User Logic
459		------------------------------------------
460		i_data_rec : entity work.data_rec
461			generic map (
462				NumOfInputs_g	=> NumOfInputs_g,
463				InputWidth_g	=> InputWidth_g,
464				MemoryDepth_g	=> MemoryDepth_g,
465				TrigInputs_g	=> TrigInputs_g
466			)
467			port map
468			(
469				-- Control Signals
470				Clk				=> Clk,
471				Rst				=> RstProc,
472				-- Data Ports
473				In_Data0		=> In_Data0,			
474				In_Data1		=> In_Data1,			
475				In_Data2		=> In_Data2,			
476				In_Data3		=> In_Data3,			
477				In_Data4		=> In_Data4,			
478				In_Data5		=> In_Data5,			
479				In_Data6		=> In_Data6,			
480				In_Data7		=> In_Data7,			
481				In_Vld			=> In_Vld,		
482				-- Trigger Ports
483				Trig_In			=> Trig_In,
484				Trig_Out		=> Trig_Out,
485				-- Register Ports
486				State			=> port_stat_state,
487				Arm				=> port_cfg_arm,
488				Ack				=> port_cfg_ack,
489				PreTrigSpls		=> port_pretrig,
490				TotalSpls		=> port_totspl,			
491				SelfTrigLo		=> port_selftriglo,
492				SelfTrigHi		=> port_selftrighi,
493				SelfTrigChEna	=> port_selftrigchena,
494				SelfTrigOnExit	=> port_selftrigonexit,
495				SelfTrigOnEnter	=> port_selftrigonenter,
496				SwTrig			=> port_swtrig,
497				Done			=> port_done,
498				TrigCntClr		=> port_cfg_trigcntclr,
499				TrigCnt			=> port_trigcnt,
500				DoneTime		=> port_donetime,
501				TrigEna			=> port_trigena,
502				EnableExtTrig	=> port_enableexttrig,
503				MinRecPeriod	=> port_minrecperiod,
504				-- Memory Ports
505				Mem_Wr			=> RecMemWr,
506				Mem_Adr			=> RecMemAdr,
507				Mem_Data		=> RecMemData,
508				FirstSplAddr	=> FirstSplAddr
509			);
510			
511		-- For power of 2 memory depth, the address logic is relatively simple
512		g_pwr2mem : if not NonPwr2MemDepth_c generate
513			AxiMemAdr		<= std_logic_vector(unsigned(mem_addr(log2ceil(MemoryDepth_g)+1 downto 2)) + unsigned(FirstSplAddr));
514		end generate;
515		
516		-- For non power of 2 memory depth, the address logic is more complex and prone to slow timing, therefore it is only implemented if required
517		g_npwr2mem : if NonPwr2MemDepth_c generate
518			signal AxiMemAddrUnwrapped 	: std_logic_vector(AxiMemAdr'high+1 downto 0);
519			signal MemAddrFull			: std_logic_vector(AxiMemAddrUnwrapped'range);
520		begin
521			AxiMemAddrUnwrapped		<= std_logic_vector(unsigned(mem_addr(log2ceil(MemoryDepth_g)+1 downto 2)) + unsigned('0' & FirstSplAddr));
522			MemAddrFull				<= AxiMemAddrUnwrapped when unsigned(AxiMemAddrUnwrapped) < MemoryDepth_g else 
523									   std_logic_vector(unsigned(AxiMemAddrUnwrapped) - MemoryDepth_g);
524			AxiMemAdr				<= MemAddrFull(AxiMemAdr'range);
525		end generate;
526			
527		
528		mem_read_mux : process(s00_axi_aclk)
529		begin
530			if rising_edge(s00_axi_aclk) then
531				AxiMemSel		<= mem_addr(log2ceil(MemoryDepth_g)+4 downto log2ceil(MemoryDepth_g)+2);
532			end if;
533		end process;
534		mem_rdata(31 downto InputWidth_g)	<= 	(others => mem_rdata(InputWidth_g-1)); --sign extension
535		mem_rdata(InputWidth_g-1 downto 0) 	<= 	AxiMemOut(0) when unsigned(AxiMemSel) = 0 else
536												AxiMemOut(1) when unsigned(AxiMemSel) = 1 else
537												AxiMemOut(2) when unsigned(AxiMemSel) = 2 else
538												AxiMemOut(3) when unsigned(AxiMemSel) = 3 else
539												AxiMemOut(4) when unsigned(AxiMemSel) = 4 else
540												AxiMemOut(5) when unsigned(AxiMemSel) = 5 else
541												AxiMemOut(6) when unsigned(AxiMemSel) = 6 else
542												AxiMemOut(7);
543		
544		
545		g_mem : for i in 0 to NumOfInputs_g-1 generate
546		begin	
547			i_mem : entity work.psi_common_tdp_ram
548				generic map (
549					depth_g		=> MemoryDepth_g,
550					width_g		=> InputWidth_g,
551					behavior_g	=> "RBW"
552				)
553				port map (
554					-- Port A
555					a_clk_i		=> Clk,
556					a_addr_i		=> RecMemAdr,
557					a_wr_i			=> RecMemWr,
558					a_dat_i		=> RecMemData((i+1)*InputWidth_g-1 downto i*InputWidth_g),
559					a_dat_o		=> open,
560					
561					-- Port B
562					b_clk_i		=> s00_axi_aclk,
563					b_addr_i		=> AxiMemAdr,
564					b_wr_i			=> '0',
565					b_dat_i		=> (others => '0'),
566					b_dat_o		=> AxiMemOut(i)
567				);
568		end generate;
569	  
570	end rtl;
571

